INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Multilingual text-to-speech$q$, $q$Generate natural, emotionally expressive speech from text in dozens of languages using a large library of stock AI voices.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Instant and professional voice cloning$q$, $q$Clone a voice from a short sample for quick use, or train a higher-fidelity professional clone from a longer recording.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$AI dubbing studio$q$, $q$Automatically translate and re-voice video or audio content into another language while preserving the original speaker's tone and timing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Speech-to-text transcription$q$, $q$Convert spoken audio into accurate text transcripts, useful for captioning and content repurposing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Conversational AI agents$q$, $q$Build low-latency voice agents for phone systems, customer support, and in-app assistants using API and SDK tooling.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Sound effects and music generation$q$, $q$Generate short sound effects and music tracks from text prompts for use in video, games, and podcasts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Developer API and SDKs$q$, $q$Access every ElevenLabs capability programmatically to embed voice generation directly into third-party products.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Commercial licensing$q$, $q$Paid tiers from Starter upward include a commercial license covering generated audio, voice clones, and dubbed content.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Widely regarded as producing some of the most natural, human-like AI voices available$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Combines text-to-speech, cloning, dubbing, and conversational agents in one platform and one credit pool$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Generous free tier and low-cost Starter plan make it accessible to individual creators$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Robust developer API makes it easy to embed voice generation into other products$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Credit consumption can escalate quickly for high-volume commercial use, making costs hard to predict$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Professional voice cloning and team seats are locked behind mid-tier and higher plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Enterprise pricing is not publicly disclosed and requires a sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Voice cloning technology has raised misuse and deepfake concerns industry-wide, prompting added verification steps$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Is ElevenLabs free to use?$q$, $q$Yes, ElevenLabs offers a Free plan with 10,000 monthly credits, but generated audio on the Free plan is limited to non-commercial use. Commercial rights start on the Starter plan at $6/month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$What languages does ElevenLabs support?$q$, $q$ElevenLabs' text-to-speech and dubbing models support dozens of languages, and its voices can speak most major world languages with natural pronunciation.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Can I clone my own voice with ElevenLabs?$q$, $q$Yes. Instant Voice Cloning is available from the Starter plan using a short audio sample, while Professional Voice Cloning, available from the Creator plan, produces a higher-fidelity clone from a longer recording.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Does ElevenLabs have an API?$q$, $q$Yes, ElevenLabs provides a REST API and official SDKs so developers can integrate text-to-speech, voice cloning, dubbing, and conversational agents into their own applications.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$How does ElevenLabs pricing work?$q$, $q$ElevenLabs uses a monthly credit system. Higher-priced plans, from Starter through Business, include more credits, higher audio quality, additional workspace seats, and more voice clones, with a custom Enterprise tier for large-scale needs.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Who founded ElevenLabs and when?$q$, $q$ElevenLabs was founded in 2022 by Piotr DД…bkowski and Mati Staniszewski, and is headquartered in New York City with offices in London and Warsaw.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Audiobook and podcast narration$q$, $q$Creators and publishers use ElevenLabs to generate natural-sounding narration and convert written content into audio at a fraction of the cost of studio voice talent.$q$, $q$Independent creators, podcasters, and publishers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Video localization and dubbing$q$, $q$Media teams use the AI Dubbing Studio to translate and re-voice video content into multiple languages while preserving the original speaker's tone.$q$, $q$Media companies and video production teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Voice agents for customer support$q$, $q$Enterprises build low-latency conversational voice agents on ElevenLabs' API to handle phone-based customer service and in-app voice assistants.$q$, $q$Enterprise product and customer support teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["10,000 credits/month","Text to speech, speech to text, sound effects","Voice design and music","3 Studio projects","Non-commercial use only"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Starter$q$, $q$$6/month ($5/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["30,000 credits/month","Commercial license","Instant voice cloning","20 Studio projects","Dubbing studio access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Creator$q$, $q$$22/month ($18.33/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["121,000 credits/month","Professional voice cloning","Everything in Starter","50% off first month"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Pro$q$, $q$$99/month ($82.50/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["600,000 credits/month","44.1kHz PCM audio via API","192kbps audio quality","Everything in Creator"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Scale$q$, $q$$299/month ($249.17/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["1,800,000 credits/month","3 workspace seats","3 professional voice clones","Team collaboration"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Business$q$, $q$$990/month ($825/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["6,000,000 credits/month","10 workspace seats","10 professional voice clones","Low-latency TTS options"]$q$::jsonb, 5);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$Enterprise$q$, $q$Custom quote$q$, $q$Custom$q$, NULL, $q$["Custom credit volumes","DPA/SLA and HIPAA-ready BAAs","Custom SSO","Priority support and managed dubbing"]$q$::jsonb, 6);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ElevenLabs builds AI models that generate lifelike speech, clone voices, translate and dub video, and power real-time conversational voice agents. Founded in 2022 by Piotr DД…bkowski and Mati Staniszewski, the company is headquartered in New York City with additional teams in London and Warsaw.$q$, $q$The platform is accessed through a web-based Speech Studio for creators and a developer API for teams embedding voice into their own products, with usage across both metered on a shared monthly credit system.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include multilingual text-to-speech with a large stock voice library, instant and professional voice cloning, speech-to-text transcription, an AI dubbing studio for localizing video, a sound-effects generator, AI music generation, and a Conversational AI framework for building voice agents.$q$, $q$Developers can integrate any of these capabilities through a REST API and official SDKs, making ElevenLabs a common voice backend inside third-party apps, games, and customer support tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ElevenLabs uses a freemium, credit-based pricing model with seven tiers: Free, Starter ($6/month), Creator ($22/month), Pro ($99/month), Scale ($299/month), Business ($990/month), and a custom-quoted Enterprise tier.$q$, $q$Each tier raises the monthly credit allowance, unlocks higher-fidelity audio and more workspace seats, and adds commercial usage rights; annual billing on any paid plan works out to roughly two months free compared with paying monthly.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('800f1735-5876-4cb4-b6d8-d7bee24e7a9f', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Multi-template-language support$q$, $q$Write pages in Markdown, Nunjucks, Liquid, Handlebars, Pug, EJS, HAML, or plain HTML, all within the same project.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Zero required client-side JavaScript$q$, $q$Eleventy outputs plain static HTML by default, keeping sites fast and lightweight without forcing a JavaScript runtime on visitors.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Data cascade$q$, $q$Compose page, directory-level, and global data through JSON, JavaScript, or front-matter files for flexible content modeling.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Fast incremental builds$q$, $q$Eleventy rebuilds only what has changed during development, keeping local preview loops fast even on larger sites.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Plugin ecosystem$q$, $q$Official and community plugins add image optimization, RSS feeds, pagination, syntax highlighting, and internationalization support.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Framework-agnostic output$q$, $q$Eleventy does not require adopting React, Vue, or any other UI framework, giving developers full control over HTML output.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Deploy anywhere$q$, $q$Since the output is static HTML, sites can be hosted on any static host, CDN, or traditional web server.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Active open-source development$q$, $q$Maintained under Font Awesome stewardship since 2024, with regular releases such as version 3.0 and 3.1 improving speed and module support.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Completely free and open source with no paid tiers or usage limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Produces fast, lightweight static HTML with no required client-side JavaScript$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Supports many templating languages in the same project, easing migration from other generators$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Widely used and well-documented within the Jamstack and JavaScript communities$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Requires comfort with the command line and JavaScript tooling, unlike no-code website builders$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Smaller plugin and theme marketplace compared to larger ecosystems like WordPress$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Recent Font Awesome rebranding efforts ('Build Awesome') created community uncertainty about the project's direction$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$No built-in visual editor, so content authors need to work directly with source files or a headless CMS$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Is Eleventy free to use?$q$, $q$Yes, Eleventy is completely free and open source under the MIT license, with no paid plans or usage restrictions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Who created Eleventy?$q$, $q$Eleventy was created in 2017 by developer Zach Leatherman, and has been stewarded by Font Awesome since September 2024.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$What templating languages does Eleventy support?$q$, $q$Eleventy supports more than ten template languages, including Markdown, Nunjucks, Liquid, Handlebars, Pug, EJS, HAML, and plain HTML, often mixed within the same project.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Does Eleventy require React or another JavaScript framework?$q$, $q$No. Eleventy is framework-agnostic and outputs plain static HTML with no required client-side JavaScript, though it can integrate with front-end frameworks if desired.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Is Eleventy the same as 'Build Awesome'?$q$, $q$In March 2026, Font Awesome introduced a rebrand called Build Awesome for the project, but the rebranding and an associated fundraiser were paused shortly after, and the 11ty name remains in active use as of mid-2026.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$What is Eleventy commonly used for?$q$, $q$Eleventy is commonly used to build blogs, documentation sites, marketing pages, and portfolios where fast load times and SEO performance are priorities.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Developer blogs and documentation$q$, $q$Developers use Eleventy to build fast, SEO-friendly blogs and technical documentation sites without adopting a heavier JavaScript framework.$q$, $q$Software developers and technical writers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Jamstack marketing sites$q$, $q$Agencies and small teams use Eleventy to build performance-focused marketing and landing pages deployed to static hosts like Netlify.$q$, $q$Web agencies and marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Static portfolios and personal sites$q$, $q$Individuals use Eleventy's simple templating system to build personal portfolios and resume sites hosted for free on static hosting platforms.$q$, $q$Individual developers and designers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under MIT license","Unlimited sites and builds","Community plugin ecosystem","No usage restrictions or paid tiers"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Eleventy (11ty) is a free, open-source static site generator written in JavaScript, created in 2017 by Zach Leatherman as a simpler, more flexible alternative to Jekyll.$q$, $q$It compiles Markdown, Nunjucks, Liquid, and other template formats into fast, dependency-free static HTML, and has been stewarded by Font Awesome since 2024 with Leatherman continuing as lead maintainer.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Eleventy supports more than ten templating languages in a single project, requires zero client-side JavaScript by default, and offers a flexible data cascade for composing page, directory, and global data.$q$, $q$Its plugin ecosystem covers image optimization, RSS feeds, pagination, and internationalization, and its output is plain static HTML that can be deployed to any static host or CDN.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Eleventy is completely free and open source under the MIT license, with no paid tiers, subscriptions, or usage limits for the core software.$q$, $q$Costs, if any, come only from optional third-party hosting or CI services used to build and deploy the resulting static site, not from Eleventy itself.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d95e837c-ef43-455b-89b5-3d198bab18ed', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$User profiles and networking$q$, $q$Members create profiles and connect with one another, forming the social graph at the center of an Elgg-powered community.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Blogging and activity streams$q$, $q$Built-in blogging and microblogging tools let members post updates that flow into a community-wide or group-level activity stream.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Groups$q$, $q$Public and private groups allow communities to organize around shared interests, courses, or projects.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$File and media sharing$q$, $q$Members can upload and share files and media within their profiles or groups, with access controlled per item.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Granular access control$q$, $q$Every piece of content can be restricted to specific audiences, from fully public to a single group or individual.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Plugin architecture$q$, $q$Core functionality can be extended through community-built and third-party plugins covering themes, integrations, and specialized tools.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Self-hosted deployment$q$, $q$Organizations install Elgg on their own PHP/MySQL infrastructure, retaining full control over data and customization.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Non-profit stewardship$q$, $q$The Elgg Foundation governs ongoing development, keeping the project independent of any single commercial owner.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Completely free and open source with no licensing costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Full data ownership and control since it is entirely self-hosted$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Purpose-built for social networking, with deeper native profile, group, and access-control features than a bolted-on CMS plugin$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Long track record dating back to 2004, with proven use by universities and non-profits$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Requires self-hosting expertise and ongoing PHP/MySQL server maintenance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Smaller and less consistent plugin ecosystem than larger platforms like WordPress$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$No official marketplace, so premium plugins are scattered across independent developer sites$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Smaller, more niche community today than during the platform's peak in the late 2000s and early 2010s$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Is Elgg free to use?$q$, $q$Yes, Elgg is free and open source under a dual GPL/MIT license. There is no software licensing fee; costs come only from self-hosting infrastructure.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Who created Elgg and when?$q$, $q$Elgg was created in 2004 by Ben Werdmuller and Dave Tosh, and is now governed by the non-profit Elgg Foundation.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$What are the server requirements for Elgg?$q$, $q$The current version of Elgg requires PHP 8.1 or higher, roughly 256MB of PHP memory, a MySQL 8 database, and a working cron scheduler for notifications and digests.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Can Elgg be used commercially?$q$, $q$Yes. Elgg's dual GPL/MIT license permits commercial use, modification, and deployment at no licensing cost.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Who typically uses Elgg?$q$, $q$Universities, non-profits, and organizations building private community platforms or internal social intranets are Elgg's most common users.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$How is Elgg different from BuddyPress?$q$, $q$Elgg is a standalone, purpose-built social networking engine, while BuddyPress is a plugin that adds social features on top of an existing WordPress installation.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$University and alumni networks$q$, $q$Universities use Elgg to build private academic communities and alumni networks with profiles, groups, and discussion features.$q$, $q$Higher education institutions$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Non-profit and advocacy communities$q$, $q$Non-profits and social causes use Elgg to run member communities and coordinate advocacy without relying on commercial social networks.$q$, $q$Non-profits and community organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Internal enterprise social intranets$q$, $q$Organizations deploy Elgg internally as a private, self-hosted social network for staff collaboration and knowledge sharing.$q$, $q$Enterprises and internal IT teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$Open Source Core$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full self-hosted source code under GPL/MIT license","User profiles, groups, blogging, and file sharing","Plugin and theme extensibility","No licensing fees"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Elgg is a free, open-source social networking engine created in 2004 by Ben Werdmuller and Dave Tosh, giving organizations the tools to build their own private community platforms rather than relying on commercial social networks.$q$, $q$Now governed by the non-profit Elgg Foundation, it is built on PHP and MySQL and dual-licensed under the GPL and MIT licenses, making it free to self-host for commercial or non-commercial use.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Elgg's core provides user profiles, blogging and activity streams, public and private groups, file sharing, and granular access controls out of the box.$q$, $q$Additional functionality is added through a plugin architecture, and communities are extended through custom themes and third-party or community-built plugins.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Elgg itself is completely free and open source with no licensing fee, but organizations must budget for self-hosting infrastructure, which can start from a few dollars a month on shared hosting for small communities.$q$, $q$There is no official paid tier; larger deployments typically pay for higher-capacity hosting and, optionally, custom development or support services from the community.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('52d15888-e7a1-4bf4-a86f-407a65530036', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Braindump task capture$q$, $q$Quickly capture every task or idea into an unstructured list without assigning time or priority upfront.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Drag-and-drop day timeline$q$, $q$Visually schedule braindump tasks onto a Kanban-style timeline to timebox an entire day.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Recurring tasks and subtasks$q$, $q$Set up repeating tasks and break larger items into subtasks for more granular planning.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Unlimited labels$q$, $q$Organize tasks by project, context, or category using an unlimited number of custom labels.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Calendar integrations$q$, $q$Sync with Google Calendar and Apple Calendar so scheduled tasks and existing events appear together.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Siri Shortcuts support$q$, $q$Quickly add tasks to Ellie using Siri Shortcuts on Apple devices.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Time tracking and analytics$q$, $q$Track time spent on tasks and view basic analytics on how a day or week was actually spent.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Multi-platform native apps$q$, $q$Native apps for iOS, macOS, and Windows, plus a web app, provide broader coverage than most mobile-first planners.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Free plan offers genuinely unlimited task creation with no credit card required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Native apps for iOS, macOS, and Windows in addition to the web, unusual for a planner app of its size$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$One-time lifetime purchase option available for users who prefer not to subscribe$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Simple, focused two-step brain-dump-then-schedule workflow that is easy to learn$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$No native Android app, leaving Android users limited to the web app$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Built and supported largely by a single developer, which can affect the pace of updates and support$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Core timeboxing feature and calendar integrations are locked behind the paid Pro tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Smaller feature set and integration ecosystem compared to larger, team-oriented planning tools$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Is Ellie Planner free?$q$, $q$Yes, Ellie offers a free plan with unlimited task creation and braindump functionality. The Pro tier, which unlocks timebox mode and calendar integrations, costs $9.99/month or is available as a one-time lifetime purchase.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Does Ellie have an Android app?$q$, $q$No. Ellie is available on iOS, macOS, Windows, and the web, but there is currently no native Android app; Android users can use the web version.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Who built Ellie Planner?$q$, $q$Ellie was built by Chris Raroque, a solo indie developer based in Dallas, Texas, who has also worked on other projects including Mogul and Aloa.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Does Ellie integrate with Google Calendar?$q$, $q$Yes, Ellie Pro integrates with both Google Calendar and Apple Calendar so scheduled tasks appear alongside existing calendar events.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Is there a student discount for Ellie Pro?$q$, $q$Yes, Ellie offers a 50% discount off the yearly Pro price for verified students who contact support directly.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$What makes Ellie different from a regular to-do list app?$q$, $q$Ellie separates task capture from scheduling: tasks first go into an unstructured braindump list, then get dragged onto a visual day timeline to timebox them into real time, rather than sitting on a static, ever-growing list.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Daily timeboxing for knowledge workers$q$, $q$Individuals practicing timeboxing use Ellie to convert a loose task list into a realistic, scheduled day plan.$q$, $q$Knowledge workers and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Student task and deadline management$q$, $q$Students use Ellie's due dates, recurring tasks, and calendar sync to manage coursework and personal deadlines, with a discounted student plan available.$q$, $q$Students$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Cross-device personal planning$q$, $q$Users who work across iPhone, Mac, and Windows machines use Ellie's native multi-platform apps to keep their daily plan in sync everywhere.$q$, $q$Individuals working across multiple devices$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Unlimited task creation","Braindump list","iOS and web app access","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Ellie Pro (Monthly)$q$, $q$$9.99/month$q$, $q$Monthly$q$, NULL, $q$["Timebox mode","Google Calendar integration","Apple Calendar integration","Unlimited labels and subtasks","Recurring tasks and due dates"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$Ellie Pro (Lifetime)$q$, $q$$299.99 one-time$q$, $q$One-time payment$q$, NULL, $q$["All Ellie Pro features","Single one-time payment instead of a recurring subscription"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Ellie Planner is a daily planning app built around a brain-dump task list and a drag-and-drop day timeline, created by Dallas-based solo developer Chris Raroque.$q$, $q$It is available on iOS, macOS, Windows, and the web, with a free tier for basic task capture and a paid Pro tier that unlocks timeboxing and calendar integrations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Ellie's workflow starts with an unstructured braindump area for capturing tasks, then lets users drag items onto a visual day timeline to timebox their schedule.$q$, $q$Additional features include recurring tasks, subtasks, due dates, unlimited labels, basic time tracking and analytics, and integrations with Google Calendar, Apple Calendar, and Siri Shortcuts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Ellie offers a free plan with unlimited task creation and core braindump functionality with no credit card required.$q$, $q$Ellie Pro adds timebox mode, calendar integrations, and unlimited labels and subtasks for $9.99/month, with a one-time lifetime purchase option also available and a 50% student discount on annual pricing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cdc946d2-b06d-4438-be5e-2091531fcf59', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Drag-and-drop campaign builder$q$, $q$Design newsletters and promotional emails using a visual drag-and-drop or HTML editor.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Marketing automation sequences$q$, $q$Set up automated welcome series and drip campaigns triggered by subscriber actions or sign-up date.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Audience segmentation$q$, $q$Segment subscriber lists by tags, behavior, or custom fields to send more targeted campaigns.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Landing pages and signup forms$q$, $q$Build landing pages and embeddable signup forms to grow an email list without needing a separate website.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$List management and import tools$q$, $q$Import, export, and manage subscriber lists with tools for cleaning and organizing contact data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Campaign analytics$q$, $q$Track opens, clicks, and other campaign performance metrics, retained indefinitely on paid plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Amazon SES-based sending$q$, $q$Uses Amazon Simple Email Service infrastructure to help keep sending costs, and therefore pricing, low.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Multi-user accounts$q$, $q$Pro plan supports multiple user accounts on a single workspace for small marketing teams.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Significantly cheaper than mainstream competitors like Mailchimp at comparable subscriber counts$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Genuine free plan covering 2,500 subscribers and 10,000 monthly emails with no time limit$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$20% lifetime discount available for verified non-profit organizations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Simple, focused feature set that avoids the complexity of larger all-in-one marketing suites$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Free plan statistics are only retained for 30 days and include EmailOctopus branding$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Fewer advanced CRM, e-commerce, and multichannel features than larger platforms like Brevo or HubSpot$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Small internal team may mean slower feature development compared to venture-backed competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Landing pages and forms are limited to one each on the free plan$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Is EmailOctopus free to use?$q$, $q$Yes, EmailOctopus offers a free plan covering up to 2,500 subscribers and 10,000 emails per month, with EmailOctopus branding included on campaigns.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$How much does EmailOctopus Pro cost?$q$, $q$The Pro plan starts at $9 per month for 500 subscribers with unlimited monthly sends, and the price automatically scales up as your subscriber list grows.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$When was EmailOctopus founded?$q$, $q$EmailOctopus was founded in 2014 and is headquartered in London, England.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Does EmailOctopus offer a discount for non-profits?$q$, $q$Yes, verified non-profit organizations receive a 20% lifetime discount on any paid EmailOctopus plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$What email sending infrastructure does EmailOctopus use?$q$, $q$EmailOctopus has historically built its sending infrastructure on Amazon Simple Email Service (Amazon SES), which helps it offer lower prices than competitors running their own proprietary infrastructure.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$How is EmailOctopus different from Mailchimp?$q$, $q$EmailOctopus offers a narrower, more focused feature set than Mailchimp but prices its paid plans roughly 40 to 60 percent cheaper at comparable subscriber counts, appealing to price-sensitive small businesses and creators.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Budget-friendly newsletter sending$q$, $q$Small businesses and bloggers use EmailOctopus to send regular newsletters at a fraction of the cost of larger email marketing platforms.$q$, $q$Small businesses and independent creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$List growth with landing pages$q$, $q$Solo creators and startups use EmailOctopus's built-in landing pages and signup forms to grow an email list without a separate website.$q$, $q$Startups and solo creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Automated welcome and drip sequences$q$, $q$Marketing teams set up automated welcome series and drip campaigns to nurture new subscribers without manual sending.$q$, $q$Small marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Up to 2,500 subscribers","10,000 emails/month","1 landing page and 1 form","EmailOctopus branding","30-day statistics retention"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Pro$q$, $q$From $9/month (billed annually) for 500 subscribers$q$, $q$Monthly or annual, scales with list size$q$, NULL, $q$["Unlimited monthly emails","Full control over email design","Unlimited landing pages and forms","Indefinite statistics retention","Multiple user accounts"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$Enterprise$q$, $q$Custom quote$q$, $q$Custom$q$, NULL, $q$["For accounts exceeding roughly 500,000 subscribers","Custom pricing and support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$EmailOctopus is a London-based email marketing platform founded in 2014, positioned as a lower-cost alternative to larger providers like Mailchimp.$q$, $q$The company is run by a small team of roughly ten to fifteen people, serving more than 50,000 customers who send over 19 billion emails a year through the platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality includes campaign creation, marketing automation sequences, subscriber list management, audience segmentation, and landing page and signup form builders.$q$, $q$EmailOctopus has historically relied on Amazon SES for sending infrastructure, which helps it maintain significantly lower pricing than competitors using proprietary sending infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$EmailOctopus prices around subscriber count: the Free plan covers up to 2,500 subscribers and 10,000 monthly emails, while the Pro plan starts at $9/month for 500 subscribers with unlimited sends and automatically scales as a list grows.$q$, $q$Non-profits receive a 20% lifetime discount on paid plans, and custom Enterprise pricing is available for accounts exceeding roughly 500,000 subscribers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb61be61-826d-402e-93f5-17aed2eb85a3', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$SMTP storage daemon$q$, $q$Accepts and stores incoming email messages for later forwarding or retrieval.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$SMTP forwarding agent$q$, $q$Relays stored messages onward to a designated smarthost or performs custom routing to other destinations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$POP3 server$q$, $q$Serves stored messages to local email client software using the POP3 protocol.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$External filter hooks$q$, $q$Pipes messages through a user-defined program, allowing integration with spam filters like SpamAssassin or custom editing scripts.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$DNSBL connection blocking$q$, $q$Rejects connections from known spam sources using DNS-based blocklists.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$Non-blocking I/O architecture$q$, $q$Runs as a single lightweight process using the same event-driven model as Squid and nginx for efficient resource usage.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$Cross-platform support$q$, $q$Runs on both Linux and Windows, with a graphical installation wizard available for Windows deployments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$Lightweight, dependency-light codebase$q$, $q$Written in C++ with minimal dependencies, making it easy to compile and run on constrained or older hardware.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$Completely free and open source with no licensing costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$Very lightweight and resource-efficient compared to full mail server suites$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$Flexible filtering hook lets administrators plug in SpamAssassin or custom scripts$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$Runs on both Linux and Windows with a graphical installer for Windows users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$Narrower feature set than full mail server platforms like Postfix or Exim$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$No official commercial support, so troubleshooting relies on documentation and community resources$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$Configuration is command-line and config-file driven, which requires technical comfort$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$Smaller, less active community compared to mainstream MTA projects$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$Is EmailRelay (E-MailRelay) free?$q$, $q$Yes, E-MailRelay is completely free and open source, distributed through SourceForge with no licensing fee or paid tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$What platforms does E-MailRelay support?$q$, $q$E-MailRelay runs on both Linux and Windows, and includes a graphical installation wizard for Windows deployments.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$What does E-MailRelay actually do?$q$, $q$It acts as an SMTP proxy and store-and-forward mail transfer agent, receiving, storing, optionally filtering, and forwarding email to another mail server, while also serving stored mail to local clients over POP3.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$Can E-MailRelay filter spam?$q$, $q$Yes, it can pipe incoming messages through an external program such as SpamAssassin, and supports DNSBL-based blocking to reject connections from known spam sources.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$How is E-MailRelay different from Postfix?$q$, $q$E-MailRelay is a narrower, lightweight SMTP proxy and relay rather than a full-featured production mail server like Postfix; it focuses specifically on storing, filtering, and forwarding mail rather than complete mailbox and delivery infrastructure.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$Who maintains E-MailRelay?$q$, $q$E-MailRelay is maintained as an open-source project hosted on SourceForge, without a dedicated commercial company behind it.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$Personal spam-filtering mail relay$q$, $q$Individuals and small offices run E-MailRelay as a personal internet mail server that filters spam via SpamAssassin before final delivery.$q$, $q$System administrators and small offices$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$Local development SMTP testing$q$, $q$Developers run E-MailRelay locally to capture outbound application email during testing without delivering it externally.$q$, $q$Software developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$Lightweight relay in front of production mail servers$q$, $q$Administrators deploy E-MailRelay as a store-and-forward proxy layer in front of a heavier mail server to add filtering and resilience.$q$, $q$IT and infrastructure teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code and pre-built binaries","SMTP storage, forwarding, and POP3 serving","External filter and DNSBL support","No licensing fees"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$E-MailRelay (EmailRelay) is a free, open-source SMTP proxy and store-and-forward mail transfer agent written in C++, distributed through SourceForge for Linux and Windows.$q$, $q$It is designed as a narrow, single-purpose relay rather than a full mail server platform, focusing on receiving, storing, filtering, and forwarding SMTP mail.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$E-MailRelay runs as a single non-blocking process, acting simultaneously as an SMTP storage daemon, an SMTP forwarding agent, and a POP3 server for local mail clients.$q$, $q$It supports piping messages through external filtering programs such as SpamAssassin, DNSBL-based connection blocking, and configurable routing to a fixed smarthost or custom destinations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$E-MailRelay is completely free and open source, with no paid tier, licensing fee, or commercial edition.$q$, $q$It is distributed as source code and pre-built binaries through its SourceForge project page at no cost.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('48dce657-93e5-4f57-b7c7-2ec20c859674', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Personal media library organization$q$, $q$Automatically indexes movies, TV shows, music, and photos, pulling in metadata and artwork for a polished browsing experience.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Wide client platform support$q$, $q$Native apps span Apple TV, iOS, Android, Roku, Fire TV, Chromecast, PlayStation, Xbox, smart TVs, and web browsers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$On-the-fly transcoding$q$, $q$Converts video in real time to match the format and bandwidth needs of the destination device or network.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Live TV and DVR (Premiere)$q$, $q$Records and streams over-the-air or IPTV live television content, available with an Emby Premiere subscription.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Hardware-accelerated transcoding (Premiere)$q$, $q$Uses GPU hardware acceleration for smoother, more efficient transcoding on Premiere subscriptions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Offline mobile sync (Premiere)$q$, $q$Downloads media to mobile devices for offline playback without an active server connection.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Cross-platform server deployment$q$, $q$Server software runs on Windows, macOS, Linux, FreeBSD, and many NAS devices.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Cloud sync and smart home integration (Premiere)$q$, $q$Backs up server configuration to the cloud and connects with smart home platforms for Premiere subscribers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Core server and streaming functionality are free to use indefinitely with no forced trial expiration$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Extremely wide client app support across smart TVs, consoles, mobile, and web$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Flexible Premiere pricing, including a one-time lifetime purchase option not offered by most competitors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Long-standing, mature feature set including Live TV/DVR support$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Moved from open-source to closed-source licensing in 2018, a point of concern for self-hosting purists$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Advanced features like Live TV/DVR and hardware transcoding require a paid Premiere subscription$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Smaller active development community than its fully open-source fork, Jellyfin$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Requires self-hosting on owned hardware or a NAS, unlike commercial streaming services$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Is Emby free to use?$q$, $q$Yes, Emby's core media server and streaming functionality are free to use indefinitely. An optional Emby Premiere subscription unlocks advanced features like Live TV, DVR, and hardware transcoding.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$How much does Emby Premiere cost?$q$, $q$Emby Premiere is priced at $4.99/month, $54/year, or a $119 one-time lifetime purchase.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Is Emby open source?$q$, $q$Emby began as the open-source Media Browser project, but in 2018 it moved to a closed-source, proprietary model. This change led to the creation of Jellyfin, a fully open-source fork of Emby.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$What is the difference between Emby and Jellyfin?$q$, $q$Jellyfin is a free, fully open-source fork of Emby created after Emby moved to closed-source licensing in 2018. Emby remains free for core use but is closed-source and offers an optional paid Premiere tier, while Jellyfin is entirely open source with no paid tier.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$What platforms does Emby support?$q$, $q$Emby server runs on Windows, macOS, Linux, FreeBSD, and various NAS devices, while client apps are available on Apple TV, iOS, Android, Roku, Fire TV, Chromecast, PlayStation, Xbox, smart TVs, and web browsers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Who created Emby?$q$, $q$Emby was created by developer Luke Pulverenti, evolving out of his earlier open-source Media Browser project for Windows Media Center before being rebranded as Emby in 2015.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Home movie and TV streaming$q$, $q$Households use Emby to organize and stream their personal movie and TV collections to smart TVs and streaming devices throughout the home.$q$, $q$Home media enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Live TV and DVR replacement$q$, $q$Emby Premiere subscribers use Live TV and DVR functionality to record and stream over-the-air or IPTV broadcasts without a traditional cable box.$q$, $q$Cord-cutters and home theater enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Remote access to a home media library$q$, $q$Users access their self-hosted media library remotely on mobile devices while traveling, using on-the-fly transcoding to adapt to available bandwidth.$q$, $q$Frequent travelers and remote media consumers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Core media server and library organization","Streaming to supported client apps","On-the-fly transcoding","No time limit"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Emby Premiere (Monthly)$q$, $q$$4.99/month$q$, $q$Monthly$q$, NULL, $q$["Live TV and DVR","Hardware-accelerated transcoding","Offline mobile sync","Cloud sync and smart home integration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Emby Premiere (Annual)$q$, $q$$54/year$q$, $q$Annual$q$, NULL, $q$["All Emby Premiere features at a discounted annual rate"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$Emby Premiere (Lifetime)$q$, $q$$119 one-time$q$, $q$One-time payment$q$, NULL, $q$["All Emby Premiere features","Permanent access with a single upfront payment"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Emby is a personal media server that organizes a user's own movies, TV shows, music, and photos and streams them to nearly any device, evolving out of the open-source Media Browser project for Windows Media Center before rebranding as Emby in 2015.$q$, $q$In 2018 Emby moved from an open-source model to a closed-source, proprietary one, a change that directly led to the creation of the fully open-source Jellyfin fork; Emby's core server remains free to use today even though its codebase is no longer fully open source.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Emby server indexes and organizes a personal media library with metadata and artwork, and transcodes video on the fly for playback across an unusually wide range of client platforms, including smart TVs, game consoles, and mobile devices.$q$, $q$Emby Premiere, the paid tier, adds Live TV and DVR recording, hardware-accelerated transcoding, offline mobile sync, cloud backup, and smart home integrations on top of the free base experience.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Emby's core server and streaming functionality are free to use indefinitely, with no time limit or forced trial expiration.$q$, $q$Emby Premiere is available for $4.99/month, $54/year, or a $119 one-time lifetime purchase, unlocking Live TV/DVR, hardware transcoding, and other advanced features.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
