INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('243b00aa-9aa3-4490-8b1b-0156281eda01', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Social media publishing and scheduling$q$, $q$Plan, schedule, and publish content across major social platforms from a single content calendar.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Social media analytics and benchmarking$q$, $q$Measure campaign performance and benchmark against competitors using inherited Socialbakers analytics technology.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Unified social customer care inbox$q$, $q$Manage customer service inquiries from multiple social and messaging channels in one unified agent inbox.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$AI-assisted customer care automation$q$, $q$Use AI-driven automation and suggested responses to help support teams handle high volumes of customer inquiries.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Ratings and reviews management$q$, $q$Collect, monitor, and respond to customer ratings and reviews as part of the Social Commerce pillar.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Social commerce integration$q$, $q$Connect social content and engagement directly to on-site shopping experiences to drive conversions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Unlimited user licenses$q$, $q$All Emplifi plans include unlimited user seats rather than charging per additional team member.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Unlimited owned profile connections$q$, $q$Connect an unlimited number of owned brand social profiles across supported platforms on any plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Combines social marketing, customer care, and commerce in one connected platform rather than requiring separate tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Unlimited user licenses and unlimited owned profile connections on all plans, unusual in an industry that typically charges per seat$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Deep analytics heritage inherited from Socialbakers, a well-established social analytics brand$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Recognized as a Leader by Gartner in the social customer experience space in 2026$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Pricing for Social Care and Social Commerce is entirely custom-quoted with nothing published publicly$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Published Social Marketing starting prices, from roughly $1,249/month, put it out of reach for small businesses and solo marketers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Some of the most advanced 'Intelligent' AI-driven features are not yet generally available across all product lines$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Enterprise-focused positioning means a sales conversation is required to get full pricing for most of the suite$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$How much does Emplifi cost?$q$, $q$Emplifi's Social Marketing product publishes starting prices of roughly $1,249/month for the Essential tier and $2,499/month for Advanced, while Social Care, Social Commerce, and the top Intelligent tiers are priced via custom quote.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$When was Emplifi founded?$q$, $q$Emplifi was formed in June 2021 through the rebranding and merger of Socialbakers and Astute Solutions, the latter of which was originally founded in 1995.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Where is Emplifi headquartered?$q$, $q$Emplifi is headquartered in Columbus, Ohio, United States, with employees across North America, Europe, and Asia.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$What products does Emplifi offer?$q$, $q$Emplifi's suite is organized into three pillars: Social Marketing for publishing and analytics, Social Care for unified customer service, and Social Commerce for connecting social engagement to on-site shopping and reviews.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Does Emplifi charge per user seat?$q$, $q$No. Emplifi states that all of its plans include unlimited user licenses and unlimited owned social profile connections, with pricing scaled to business outcomes instead of seat count.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Who are Emplifi's main competitors?$q$, $q$Emplifi competes primarily with Sprinklr, Hootsuite, Sprout Social, and Khoros across enterprise social media marketing and customer care.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Enterprise social media marketing at scale$q$, $q$Large consumer brands use Emplifi's Social Marketing tools to plan, publish, and analyze content across many social accounts and regions.$q$, $q$Enterprise marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Unified social customer service$q$, $q$Customer support organizations use Emplifi's Social Care inbox and AI-assisted automation to manage high volumes of inquiries across social and messaging channels.$q$, $q$Enterprise customer support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Social-driven commerce and reviews$q$, $q$Retail and e-commerce brands use Emplifi's Social Commerce tools to manage ratings, reviews, and social-to-shopping conversion.$q$, $q$Retail and e-commerce brands$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Social Marketing Essential$q$, $q$From $1,249/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited user licenses","Unlimited owned profile connections","Social publishing and scheduling","Core analytics and benchmarking"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Social Marketing Advanced$q$, $q$From $2,499/month$q$, $q$Monthly$q$, NULL, $q$["Everything in Essential","Deeper collaboration tools","Expanded analytics for mid-sized teams"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Social Marketing Intelligent$q$, $q$Custom quote$q$, $q$Custom$q$, NULL, $q$["Built for large, complex enterprise operations","Advanced AI-driven marketing capabilities"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Social Care Essential$q$, $q$Custom quote$q$, $q$Custom$q$, NULL, $q$["Unified social and messaging inbox","Core customer care workflows"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Social Care Advanced$q$, $q$Custom quote$q$, $q$Custom$q$, NULL, $q$["Faster workflows for growing support teams","AI-assisted response tools"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Social Commerce Essential$q$, $q$Custom quote$q$, $q$Custom$q$, NULL, $q$["Ratings and reviews management","Foundational social commerce tools"]$q$::jsonb, 5);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$Social Commerce Advanced$q$, $q$Custom quote$q$, $q$Custom$q$, NULL, $q$["Optimized customer experience tools for growing brands","Expanded commerce integrations"]$q$::jsonb, 6);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Emplifi is an enterprise customer experience platform formed in June 2021 from the merger of Socialbakers, a social media analytics company, and Astute Solutions, a customer engagement company founded in 1995.$q$, $q$Headquartered in Columbus, Ohio, with roughly 540-550 employees across North America, Europe, and Asia, Emplifi is backed by investors including Sixth Street and Audax Private Equity at a valuation of around $1 billion.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform is organized into three pillars: Social Marketing for publishing, scheduling, and analytics; Social Care for unified customer service across social and messaging channels; and Social Commerce for connecting social engagement to on-site shopping and reviews.$q$, $q$Emplifi is increasingly positioned around AI-driven 'Autonomous Customer Experience' automation, with some of its most advanced predictive features in the Intelligent tiers still in the process of general rollout.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e87fe27-ae20-4a92-8b43-5f6016f6f4fa', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Emplifi prices each of its three product pillars in Essential, Advanced, and Intelligent tiers. Social Marketing publishes starting prices of roughly $1,249/month for Essential and $2,499/month for Advanced, with Intelligent custom-quoted.$q$, $q$Social Care and Social Commerce tiers are entirely custom-quoted, and Emplifi states that all plans include unlimited user licenses and unlimited owned social profile connections, with pricing scaled to business outcomes rather than seat count.$q$]::text[], 2);
